    /**
     * Heuristic to determine if the current buffer looks like binary content.
     * Reader will already hopefully be decoded correctly, so a bunch of NULLs indicates a binary file
     */
    private static boolean hasBinaryContent(ByteBuffer byteData) {
        if (byteData == null || byteData.remaining() == 0) return false;

        int nulls = 0;
        int total = Math.min(byteData.remaining(), 512); // check first 512 bytes for efficiency

        for (int i = 0; i < total; i++) {
            if (byteData.get(i) == 0) {
                nulls++;
            }
        }

        // If more than 15% of the initial bytes are null, consider it binary
        return (double) nulls / total > 0.15;
    }
}

